import React, {useState} from 'react';

const demoUsers = [
  {id:1,name:'John Doe',role:'Member',email:'john@example.com',status:'Active'},
  {id:2,name:'Jane Smith',role:'Admin',email:'jane@example.com',status:'Active'},
  {id:3,name:'Mike Johnson',role:'Staff',email:'mike@example.com',status:'Active'},
  {id:4,name:'Sarah Williams',role:'Member',email:'sarah@example.com',status:'Inactive'},
]

const Users = ()=>{
  const [filter,setFilter] = useState('All');
  const [users,setUsers] = useState(demoUsers);

  const toggleStatus = (id)=>{
    setUsers(u=>u.map(x=> x.id===id? {...x, status: x.status==='Active'?'Inactive':'Active'}:x));
  }

  const list = users.filter(u=> filter==='All' || u.role===filter);

  return (
    <div>
      <h3>Manage Users</h3>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
        <div style={{display:'flex',gap:8}}>
          <input className="input" placeholder="Search by name or email" />
          <select className="input" value={filter} onChange={e=>setFilter(e.target.value)}>
            <option>All</option>
            <option>Admin</option>
            <option>Staff</option>
            <option>Member</option>
          </select>
        </div>
        <button className="btn">+ Add User</button>
      </div>

      <div className="table">
        <table>
          <thead>
            <tr><th>Name</th><th>Role</th><th>Email</th><th>Status</th><th>Actions</th></tr>
          </thead>
          <tbody>
            {list.map(u=> (
              <tr key={u.id}>
                <td>{u.name}</td>
                <td>{u.role}</td>
                <td>{u.email}</td>
                <td>{u.status}</td>
                <td>
                  <button className="btn secondary" onClick={()=>toggleStatus(u.id)}>{u.status==='Active'?'Suspend':'Activate'}</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

    </div>
  );
}
export default Users;
